"use server";

import prisma from "@/lib/prisma";
import { verifyToken } from "@/lib/auth";
import { sendAdminChatNotification, sendUserChatNotification } from "@/lib/mail";

/**
 * Envoie un message
 */
export async function sendMessageAction(token: string, content: string, recipientUserId?: string) {
  try {
    const decoded = verifyToken(token);
    if (!decoded) return { success: false, error: "Non autorisé" };

    const sender = await prisma.user.findUnique({
      where: { id: decoded.userId },
      select: { id: true, role: true, firstName: true, lastName: true, email: true }
    });

    if (!sender) return { success: false, error: "Utilisateur introuvable" };

    // Si admin envoie à un user spécifique, ou user envoie (crée/trouve sa propre conv)
    const targetUserId = sender.role === 'ADMIN' ? recipientUserId : sender.id;

    if (!targetUserId) return { success: false, error: "Destinataire manquant" };

    // Trouver ou créer la conversation
    let conversation = await prisma.conversation.findUnique({
      where: { userId: targetUserId }
    });

    if (!conversation) {
      conversation = await prisma.conversation.create({
        data: { userId: targetUserId }
      });
    }

    const message = await prisma.message.create({
      data: {
        conversationId: conversation.id,
        content,
        senderId: sender.id,
        senderRole: sender.role,
        isRead: false
      }
    });

    // Mettre à jour le timestamp de la conversation
    await prisma.conversation.update({
      where: { id: conversation.id },
      data: { updatedAt: new Date() }
    });

    // Notifications E-mail
    if (sender.role === 'USER') {
      const userName = `${sender.firstName || ''} ${sender.lastName || ''}`.trim() || sender.id;
      // Optionnel: Envoyer seulement si l'admin n'est pas déjà sur la page ? 
      // Pour l'instant on envoie toujours pour être sûr.
      await sendAdminChatNotification(userName, sender.id, content.substring(0, 100));
    } else {
      // Admin répond
      const targetUser = await prisma.user.findUnique({
        where: { id: targetUserId },
        select: { email: true }
      });
      if (targetUser) {
        await sendUserChatNotification(targetUser.email, content.substring(0, 100));
      }
    }

    return { success: true, message };
  } catch (error) {
    console.error("Erreur sendMessageAction:", error);
    return { success: false, error: "Erreur serveur" };
  }
}

/**
 * Récupère les messages d'une conversation
 */
export async function getMessagesAction(token: string, userId?: string) {
  try {
    const decoded = verifyToken(token) as { userId: string } | null;
    if (!decoded) return { success: false, error: "Non autorisé" };

    const requester = await prisma.user.findUnique({
      where: { id: decoded.userId },
      select: { role: true, id: true }
    });

    if (!requester) return { success: false, error: "Utilisateur introuvable" };

    const targetId = (requester.role === 'ADMIN' && userId) ? userId : requester.id;

    const conversation = await prisma.conversation.findUnique({
      where: { userId: targetId },
      include: {
        messages: {
          orderBy: { createdAt: 'asc' }
        }
      }
    });

    return { success: true, messages: conversation?.messages || [] };
  } catch (error) {
    return { success: false, error: "Erreur serveur" };
  }
}

/**
 * Liste toutes les conservations (Admin)
 */
export async function getAdminChatListAction(token: string) {
  try {
    const decoded = verifyToken(token) as { userId: string } | null;
    if (!decoded) return { success: false, error: "Non autorisé" };

    const admin = await prisma.user.findUnique({
      where: { id: decoded.userId }
    });

    if (!admin || admin.role !== 'ADMIN') return { success: false, error: "Accès refusé" };

    const conversations = await prisma.conversation.findMany({
      include: {
        user: {
          select: { id: true, firstName: true, lastName: true, email: true }
        },
        messages: {
          orderBy: { createdAt: 'desc' },
          take: 1
        }
      },
      orderBy: { updatedAt: 'desc' }
    });

    return { success: true, conversations };
  } catch (error) {
    return { success: false, error: "Erreur serveur" };
  }
}

/**
 * Marquer comme vu
 */
export async function markAsReadAction(token: string, conversationId: string) {
    try {
        const decoded = verifyToken(token);
        if (!decoded) return { success: false, error: "Non autorisé" };

        const user = await prisma.user.findUnique({
            where: { id: decoded.userId }
        });

        if (!user) return { success: false, error: "Utilisateur introuvable" };

        // On marque comme lus les messages qui n'ont pas été envoyés par celui qui fait l'action
        await prisma.message.updateMany({
            where: {
                conversationId,
                isRead: false,
                senderRole: user.role === 'ADMIN' ? 'USER' : 'ADMIN'
            },
            data: { isRead: true }
        });

        return { success: true };
    } catch (error) {
        return { success: false, error: "Erreur serveur" };
    }
}

"use server";

import prisma from "@/lib/prisma";
import { startOfDay, differenceInDays } from 'date-fns';
import { sendLowCreditsEmail } from '@/lib/mail';

/**
 * Assure que les crédits de l'utilisateur sont réinitialisés s'il s'agit d'une nouvelle semaine (Forfait FREE)
 */
async function ensureWeeklyReset(userId: string) {
  if (!userId) return;

  try {
    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { 
        id: true, 
        plan: true, 
        credits: true, 
        lastCreditReset: true 
      }
    });

    if (!user || user.plan !== 'FREE') return;

    const now = new Date();
    const lastReset = user.lastCreditReset ? new Date(user.lastCreditReset) : null;

    // Si on a jamais reset, ou si le dernier reset date de plus de 7 jours
    if (!lastReset || differenceInDays(now, lastReset) >= 7) {
      console.log(`[Credits] Réinitialisation hebdomadaire pour ${userId} (Dernier reset: ${lastReset})`);
      await prisma.user.update({
        where: { id: userId },
        data: {
          credits: 3, // Réinitialisé à 3 (non cumulable par semaine)
          lastCreditReset: now
        }
      });
    }
  } catch (error) {
    console.error("[Credits] Erreur lors de la réinitialisation hebdomadaire:", error);
  }
}

/**
 * Récupère le nombre de crédits restants pour un utilisateur.
 * Renvoie un grand nombre (999999) si l'utilisateur est admin (Illimité)
 */
export async function fetchUserCredits(userId: string) {
  if (!userId) return 0;

  try {
    await ensureWeeklyReset(userId);

    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { credits: true, role: true },
    });

    if (user?.role === 'ADMIN') return 999999;
    return user?.credits ?? 0;
  } catch {
    return 0;
  }
}

/**
 * Vérifie si un utilisateur a encore des crédits sans en déduire (pour le pré-traitement)
 */
export async function checkCredits(userId: string) {
  if (!userId) return { success: false, error: "ID utilisateur manquant." };

  try {
    await ensureWeeklyReset(userId);

    const user = await prisma.user.findUnique({ where: { id: userId } });
    if (!user) return { success: false, error: "Utilisateur introuvable." };

    if (user.role === 'ADMIN') {
      return { success: true, isUnlimited: true };
    }

    if (user.credits <= 0) {
      return { success: false, error: "Crédits épuisés" };
    }

    return { success: true, isUnlimited: false, currentCredits: user.credits };
  } catch {
    return { success: false, error: "Impossible de vérifier les crédits." };
  }
}

/**
 * Déduit un crédit de manière sécurisée et atomique.
 * Ne déduit rien si le compte est admin.
 */
export async function deductCredit(userId: string) {
  if (!userId) return { success: false, error: "ID utilisateur manquant." };

  try {
    await ensureWeeklyReset(userId);

    const user = await prisma.user.findUnique({ where: { id: userId } });
    if (!user) return { success: false, error: "Utilisateur introuvable." };

    if (user.role === 'ADMIN') {
      return { success: true, creditsRemaining: 999999 };
    }

    if (user.credits <= 0) {
      return { success: false, error: "Crédits épuisés" };
    }

    const updatedUser = await prisma.user.update({
      where: { id: userId },
      data: {
        credits: { decrement: 1 },
        totalCreditsUsed: { increment: 1 }
      },
    });

    // Alerte si crédits épuisés
    if (updatedUser.credits === 0) {
      // Fire-and-forget pour ne pas bloquer le matching
      sendLowCreditsEmail(updatedUser.email, updatedUser.plan).catch(err => {
        console.error("[Credits:EmailAlertFailed]", err);
      });
    }

    return { success: true, creditsRemaining: updatedUser.credits };
  } catch {
    return { success: false, error: "Erreur lors de la déduction du crédit." };
  }
}

"use server";

import prisma from "@/lib/prisma";
import { verifyToken } from "@/lib/auth";
import { logInfo, logError } from "./logger.action";

/**
 * Enregistre le feedback d'un utilisateur sur un matching spécifique
 */
export async function submitMatchFeedbackAction(token: string, recordId: string, rating: number, comment?: string) {
  try {
    const session = verifyToken(token);
    if (!session) return { success: false, error: "Session expirée." };

    const record = await prisma.matchRecord.findUnique({
      where: { id: recordId }
    });

    if (!record) return { success: false, error: "Matching introuvable." };
    if (record.userId !== session.userId) return { success: false, error: "Non autorisé." };

    await prisma.matchRecord.update({
      where: { id: recordId },
      data: {
        feedbackRating: rating,
        feedbackComment: comment || null
      }
    });

    await logInfo(`Feedback IA reçu: ${rating > 0 ? 'Positif' : 'Négatif'}`, session.userId, { recordId, comment });

    return { success: true };
  } catch (error) {
    console.error("[FeedbackAction] Erreur:", error);
    return { success: false, error: "Impossible d'enregistrer le feedback." };
  }
}

/**
 * Récupère les statistiques de qualité IA pour l'admin
 */
export async function getAIQualityStatsAction(token: string) {
  try {
    const session = verifyToken(token);
    if (!session || session.role !== 'ADMIN') return { success: false, error: "Non autorisé." };

    // Taux de satisfaction global
    const totalWithFeedback = await prisma.matchRecord.count({
      where: { feedbackRating: { not: null } }
    });

    const positiveFeedback = await prisma.matchRecord.count({
      where: { feedbackRating: 1 }
    });

    const negativeFeedbackDetails = await prisma.matchRecord.findMany({
      where: { feedbackRating: -1 },
      orderBy: { createdAt: 'desc' },
      take: 10,
      include: {
        user: { select: { firstName: true, lastName: true, email: true } }
      }
    });

    const averageScore = await prisma.matchRecord.aggregate({
      _avg: { score: true }
    });

    return {
      success: true,
      stats: {
        totalFeedbacks: totalWithFeedback,
        satisfactionRate: totalWithFeedback > 0 ? (positiveFeedback / totalWithFeedback) * 100 : 0,
        averageAIScore: averageScore._avg.score || 0
      },
      reports: negativeFeedbackDetails
    };
  } catch (error) {
    console.error("[AIQualityStats] Erreur:", error);
    return { success: false, error: "Erreur lors de la récupération des stats." };
  }
}

"use server";

import prisma from "@/lib/prisma";
import { verifyToken } from "@/lib/auth";
import { z } from "zod";

interface JWTPayload {
  userId: string;
  email: string;
  role: string;
}

const updateSchema = z.object({
  firstName: z.string().optional(),
  lastName: z.string().optional(),
  email: z.string().email().optional(),
  phone: z.string().optional(),
  role: z.enum(["ADMIN", "USER"]).optional(),
  plan: z.string().optional(),
  isActive: z.boolean().optional(),
  credits: z.number().int().optional(),
});

/**
 * Récupère la liste des utilisateurs avec pagination et recherche
 */
export async function getAdminUsersAction(token: string, page = 1, search = "") {
  try {
    const decoded = verifyToken(token);
    if (!decoded || decoded.role !== 'ADMIN') throw new Error("Accès non autorisé.");

    const pageSize = 20;
    const skip = (page - 1) * pageSize;

    const where = search ? {
      OR: [
        { email: { contains: search } },
        { firstName: { contains: search } },
        { lastName: { contains: search } },
      ]
    } : {};

    const [users, total] = await Promise.all([
      prisma.user.findMany({
        where,
        select: {
          id: true,
          email: true,
          firstName: true,
          lastName: true,
          role: true,
          plan: true,
          credits: true,
          totalCreditsUsed: true,
          isActive: true,
          createdAt: true,
        },
        orderBy: { createdAt: 'desc' },
        skip,
        take: pageSize
      }),
      prisma.user.count({ where })
    ]);

    return { 
      success: true, 
      users, 
      pagination: {
        total,
        pages: Math.ceil(total / pageSize),
        currentPage: page
      }
    };
  } catch (error: unknown) {
    const errorMsg = error instanceof Error ? error.message : "Erreur inconnue";
    return { success: false, error: errorMsg };
  }
}

/**
 * Récupère le détail complet d'un utilisateur
 */
export async function getAdminUserDetailAction(token: string, targetUserId: string) {
  try {
    const decoded = verifyToken(token);
    if (!decoded || decoded.role !== 'ADMIN') throw new Error("Accès non autorisé.");

    const user = await prisma.user.findUnique({
      where: { id: targetUserId },
      include: {
        missions: {
          orderBy: { createdAt: 'desc' },
          take: 20
        },
        candidates: {
          orderBy: { createdAt: 'desc' },
          take: 20
        }
      }
    });

    if (!user) throw new Error("Utilisateur introuvable.");

    return { success: true, user };
  } catch (error: unknown) {
    const errorMsg = error instanceof Error ? error.message : "Erreur inconnue";
    return { success: false, error: errorMsg };
  }
}

/**
 * Met à jour un utilisateur
 */
export async function updateAdminUserAction(token: string, targetUserId: string, data: any) {
  try {
    const decoded = verifyToken(token);
    if (!decoded || decoded.role !== 'ADMIN') throw new Error("Accès non autorisé.");

    const validatedData = updateSchema.parse(data);

    const updatedUser = await prisma.user.update({
      where: { id: targetUserId },
      data: validatedData
    });

    return { success: true, user: updatedUser };
  } catch (error: unknown) {
    const errorMsg = error instanceof Error ? error.message : "Erreur inconnue";
    return { success: false, error: errorMsg };
  }
}

/**
 * Ajuste les crédits manuellement
 */
export async function adjustUserCreditsAction(token: string, targetUserId: string, amount: number) {
  try {
    const decoded = verifyToken(token);
    if (!decoded || decoded.role !== 'ADMIN') throw new Error("Accès non autorisé.");

    const updatedUser = await prisma.user.update({
      where: { id: targetUserId },
      data: {
        credits: { increment: amount }
      }
    });

    return { success: true, credits: updatedUser.credits };
  } catch (error: unknown) {
    const errorMsg = error instanceof Error ? error.message : "Erreur inconnue";
    return { success: false, error: errorMsg };
  }
}

"use client";

import React, { useEffect, useState, Suspense } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { CheckCircle2, Zap, ArrowRight, Loader2, Mail } from 'lucide-react';
import Link from 'next/link';
import { syncPaymentStatusAction } from '@/actions/payment.action';

function SuccessContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const paymentId = searchParams.get('paymentId');
  const userId = searchParams.get('userId');
  const [status, setStatus] = useState<'loading' | 'success' | 'error'>(
    (paymentId || userId) ? 'loading' : 'error'
  );
  const [error, setError] = useState<string | null>(
    (paymentId || userId) ? null : "Informations de paiement manquantes."
  );

  const handleSync = React.useCallback(async () => {
    try {
      const res = await syncPaymentStatusAction(paymentId || undefined, userId || undefined);
      if (res.success) {
        setStatus('success');
      } else {
        setStatus('error');
        setError(res.error || "Impossible de valider le paiement.");
      }
    } catch (_err) {
      setStatus('error');
      setError("Une erreur technique est survenue.");
    }
  }, [paymentId, userId]);

  useEffect(() => {
    if (paymentId || userId) {
      queueMicrotask(() => {
        handleSync();
      });
    }
  }, [paymentId, userId, handleSync]);

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="max-w-md w-full bg-white rounded-[3rem] p-12 shadow-2xl shadow-slate-200 border border-slate-100 text-center animate-in fade-in zoom-in duration-500">

        {status === 'loading' && (
          <div className="space-y-6">
            <div className="w-24 h-24 bg-primary/10 rounded-full flex items-center justify-center mx-auto animate-pulse">
              <Loader2 className="w-10 h-10 text-primary animate-spin" />
            </div>
            <h1 className="text-3xl font-black text-main">Validation en cours...</h1>
            <p className="text-slate-500 font-medium">Nous finalisons la configuration de votre accès Premium. Cela ne prend que quelques secondes.</p>
          </div>
        )}

        {status === 'success' && (
          <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-700">
            <div className="w-24 h-24 bg-emerald-100 rounded-full flex items-center justify-center mx-auto">
              <CheckCircle2 className="w-12 h-12 text-emerald-500" />
            </div>

            <div className="space-y-3">
              <h1 className="text-4xl font-black text-main tracking-tight">Félicitations !</h1>
              <p className="text-slate-500 font-medium leading-relaxed">
                Votre abonnement **TalentPulse Premium** est désormais actif. Vous avez reçu 300 crédits pour commencer vos recherches.
              </p>
            </div>

            <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100 flex items-center gap-4 text-left">
              <div className="p-3 bg-white rounded-2xl shadow-sm">
                <Mail className="w-5 h-5 text-primary" />
              </div>
              <div>
                <p className="text-xs font-black text-main uppercase tracking-widest mb-0.5">Email envoyé</p>
                <p className="text-xs text-slate-500 font-bold">Un reçu vous a été envoyé par email.</p>
              </div>
            </div>

            <div className="flex flex-col gap-4">
              <Link 
                href="/dashboard"
                className="w-full py-4 bg-main text-white rounded-2xl font-black flex items-center justify-center gap-3 hover:bg-slate-800 transition-all hover:scale-[1.02] active:scale-95 shadow-xl shadow-main/20"
              >
                Accéder au Dashboard
