"use client";

import React, { useState, useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { RootState } from '@/store';
import { useRouter } from 'next/navigation';
import MatchingDashboard from '@/components/MatchingDashboard';
import MatchResultView from '@/components/MatchResultView';
import PaywallModal from '@/components/PaywallModal';
import { resetResult, setResult } from '@/store/matchingSlice';
import VivierManager from '@/components/VivierManager';
import HistoryList from '@/components/HistoryList';
import SubscriptionManager from '@/components/SubscriptionManager';
import { MatchResult } from '@/lib/ai';
import { useAuth } from '@/hooks/useAuth';
import { logout } from '@/store/userSlice';
import { LogOut, LayoutDashboard, RefreshCcw, History, Zap, CreditCard } from 'lucide-react';
import MultiMatchResultView from '@/components/MultiMatchResultView';
import { getBatchStatusAction, getActiveBatchAction, cancelActiveBatchAction } from '@/actions/matching.action';
import { setActiveBatchId, setBatchProgress, setMultiResults } from '@/store/matchingSlice';
import { CandidateInfo } from '@/lib/ai';
import { useRef } from 'react';

export default function DashboardPage() {
  const router = useRouter();
  const dispatch = useDispatch();
  const { user, isLoggedIn } = useSelector((state: RootState) => state.user);
  const credits = user?.credits ?? 0;
  const { currentResult, results, activeBatchId } = useSelector((state: RootState) => state.matching);
  const [isPaywallOpen, setIsPaywallOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'analyse' | 'vivier' | 'historique' | 'abonnement'>('analyse');

  // Gestion de la session via le hook useAuth
  useAuth();

  // Polling du batch (centralisé ici pour persister au changement de vue)
  useEffect(() => {
    let interval: NodeJS.Timeout;

    if (activeBatchId) {
      interval = setInterval(async () => {
        try {
          const response = await getBatchStatusAction(activeBatchId);
          if (response.success && 'data' in response && response.data) {
            const batch = response.data;

            dispatch(setBatchProgress({ 
              current: batch.processedItems, 
              total: batch.totalItems 
            }));

            const transformedResults = batch.items.map((item: any) => {
              if (item.status === 'COMPLETED' && item.matchRecord) {
                const aiData = (item.matchRecord.aiResponse as Record<string, unknown>) || {};
                return {
                  score: (aiData.score as number) || 0,
                  competences_validees: (aiData.competences_validees as string[]) || [],
                  competences_manquantes: (aiData.competences_manquantes as string[]) || [],
                  argumentaire_client: (aiData.argumentaire_client as string) || "Analyse terminée.",
                  questions_candidat: (aiData.questions_candidat as string[]) || [],
                  candidateInfo: (aiData.candidateInfo as CandidateInfo) || { firstName: item.candidateName || 'Candidat', lastName: '' },
                  status: item.status
                };
              }
              return { 
                status: item.status,
                score: 0,
                competences_validees: [],
                competences_manquantes: [],
                argumentaire_client: item.error || (item.status === 'PROCESSING' ? "L'IA analyse le profil..." : "En attente..."),
                questions_candidat: [],
                candidateInfo: { firstName: item.candidateName || 'Candidat', lastName: '' }
              };
            });

            dispatch(setMultiResults(transformedResults as MatchResult[]));

            if (batch.status === 'COMPLETED' || batch.status === 'FAILED') {
              dispatch(setActiveBatchId(null));
              clearInterval(interval);
            }
          } else {
            clearInterval(interval);
          }
        } catch (err) {
          console.error("Erreur polling DashboardPage:", err);
          clearInterval(interval);
        }
      }, 3000);
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [activeBatchId, dispatch]);

  const initialCheckDone = useRef(false);

  // --- Hook 1 : Détection d'un batch déjà en cours au montage ---
  useEffect(() => {
    const checkActiveBatch = async () => {
      // Éviter de vérifier si on l'a déjà fait ou si un batch est déjà actif dans le store
      if (initialCheckDone.current || activeBatchId) return;

      const activeUserId = user?.id || (typeof window !== 'undefined' ? JSON.parse(localStorage.getItem('tm_user') || '{}').id : null);
      if (!activeUserId) return;

      try {
        initialCheckDone.current = true;
        const response = await getActiveBatchAction(activeUserId);
        if (response.success && 'data' in response && response.data?.id) {
          const jobId = response.data.id;
          console.log("[DashboardPage] Reconnexion au batch actif au montage:", jobId);
          dispatch(setActiveBatchId(jobId));

          const statusRes = await getBatchStatusAction(jobId);
          if (statusRes.success && 'data' in statusRes && statusRes.data) {
            const batch = statusRes.data;
            const transformedResults = batch.items.map((item: any) => {
              if (item.status === 'COMPLETED' && item.matchRecord) {
                const aiData = (item.matchRecord.aiResponse as Record<string, unknown>) || {};
                return {
                  score: (aiData.score as number) || 0,
                  competences_validees: (aiData.competences_validees as string[]) || [],
                  competences_manquantes: (aiData.competences_manquantes as string[]) || [],
                  argumentaire_client: (aiData.argumentaire_client as string) || "Analyse terminée.",
                  questions_candidat: (aiData.questions_candidat as string[]) || [],
                  candidateInfo: (aiData.candidateInfo as CandidateInfo) || { firstName: item.candidateName || 'Candidat', lastName: '' },
                  status: item.status
                };
              }
              return { 
                status: item.status,
                score: 0,
                competences_validees: [],
                competences_manquantes: [],
                argumentaire_client: item.error || (item.status === 'PROCESSING' ? "L'IA analyse le profil..." : "En attente..."),
                questions_candidat: [],
                candidateInfo: { firstName: item.candidateName || 'Candidat', lastName: '' }
              };
            });
            dispatch(setMultiResults(transformedResults as MatchResult[]));
          }
        }
      } catch (err) {
        console.error("Erreur checkActiveBatch:", err);
      }
    };

    checkActiveBatch();
  }, [user?.id, dispatch]); // activeBatchId retiré des dépendances pour éviter la boucle

  const handleLogout = () => {
    localStorage.removeItem('tm_token');
    dispatch(logout());
    router.push('/');
  };

  // Protection de la route : rediriger vers la home si non inscrit ou en cours de chargement
  useEffect(() => {
    if (!isLoggedIn && !localStorage.getItem('tm_token')) {
      router.push('/');
    }
  }, [isLoggedIn, router]);

  if (!isLoggedIn || !user) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div>
          <p className="text-slate-400 font-bold text-sm tracking-widest uppercase animate-pulse">Initialisation du Dashboard...</p>
        </div>
      </div>
    );
  }

  const handleNewAnalysis = async () => {
    // Si un batch est actif, on l'annule côté serveur pour ne plus être "poursuivi"
    if (activeBatchId) {
      console.log("[DashboardPage] Annulation du batch actif:", activeBatchId);
      await cancelActiveBatchAction(activeBatchId);
    }

    dispatch(resetResult());
    setActiveTab('analyse');
  };

  return (
    <div className="relative min-h-screen">
      <main className="min-h-screen bg-background pb-20">

      {/* Header du Dashboard */}
      <header className="bg-white border-b border-slate-300 py-4 px-6 sticky top-0 z-30 shadow-md">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="bg-primary/10 p-2 rounded-xl">
              <LayoutDashboard className="w-6 h-6 text-primary" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-main">Dashboard Recruteur</h1>
              <p className="text-muted text-xs font-medium">👋 Bienvenue, <span className="text-primary">{user?.name || 'Recruteur'}</span></p>
            </div>
          </div>

          {/* Navigation par onglets Desktop */}
          <nav className="hidden md:flex items-center bg-slate-200 p-1.5 rounded-xl border border-slate-300">
            <TabButton 
              active={activeTab === 'analyse'} 
              onClick={() => setActiveTab('analyse')}
              icon={<RefreshCcw className="w-4 h-4" />}
              label="Analyse & Matching"
            />
            <TabButton 
              active={activeTab === 'vivier'} 
              onClick={() => setActiveTab('vivier')}
              icon={<Zap className="w-4 h-4" />}
              label="Mon Vivier IA"
            />
            <TabButton 
              active={activeTab === 'historique'} 
              onClick={() => setActiveTab('historique')}
              icon={<History className="w-4 h-4" />}
              label="Historique"
            />
            <TabButton 
              active={activeTab === 'abonnement'} 
              onClick={() => setActiveTab('abonnement')}
              icon={<CreditCard className="w-4 h-4" />}
              label="Abonnement"
            />
          </nav>

            <div className="flex items-center gap-4">
              <div className="px-4 py-2 bg-white border border-slate-300 rounded-xl flex items-center gap-3 shadow-inner">
                <span className="text-xs font-bold text-muted uppercase tracking-wider">Tes Crédits :</span>
                <span className={`text-lg font-black ${credits > 0 ? 'text-primary' : 'text-red-500'}`}>
                  {credits > 900000 ? (
                    <span className="inline-flex items-center gap-1 text-emerald-500">
                      <Zap className="w-4 h-4 fill-emerald-500" /> Illimités
                    </span>
                  ) : (
                    credits
                  )}
                </span>
              </div>
              <button 
                onClick={handleLogout}
                className="p-2.5 text-red-500 hover:bg-red-50 rounded-xl border border-transparent hover:border-red-100 transition-all group"
                title="Déconnexion"
              >
                <LogOut className="w-5 h-5 group-hover:scale-110 transition-transform" />
              </button>
            </div>
          </div>
      </header>

      {/* Navigation Mobile */}
      <div className="md:hidden sticky top-[73px] z-20 bg-white border-b border-slate-300 p-2 overflow-x-auto">
        <div className="flex gap-2 min-w-max">
          <button 
            onClick={() => setActiveTab('analyse')}
            className={`px-6 py-3 rounded-xl text-xs font-bold transition-all ${activeTab === 'analyse' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'bg-slate-100 border border-slate-200 text-muted'}`}
          >
            Analyse
          </button>
          <button 
            onClick={() => setActiveTab('vivier')}
            className={`px-6 py-3 rounded-xl text-xs font-bold transition-all ${activeTab === 'vivier' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'bg-slate-100 border border-slate-200 text-muted'}`}
          >
            Vivier
          </button>
          <button 
            onClick={() => setActiveTab('historique')}
            className={`px-6 py-3 rounded-xl text-xs font-bold transition-all ${activeTab === 'historique' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'bg-slate-100 border border-slate-200 text-muted'}`}
          >
            Historique
          </button>
          <button 
            onClick={() => setActiveTab('abonnement')}
            className={`px-6 py-3 rounded-xl text-xs font-bold transition-all ${activeTab === 'abonnement' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'bg-slate-100 border border-slate-200 text-muted'}`}
          >
            Abonnement
          </button>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 py-12">
        {activeTab === 'analyse' ? (
          <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-300 border border-slate-200 overflow-hidden">
            {results.length > 0 ? (
              <div className="p-8">
                <div className="flex justify-between items-center mb-8 pb-6 border-b border-slate-200">
                  <h2 className="text-2xl font-bold text-main">Résultat de l&apos;analyse</h2>
                  <button
                    onClick={handleNewAnalysis}
                    className="flex items-center gap-2 px-6 py-2.5 bg-slate-200 hover:bg-slate-300 text-main font-bold rounded-xl transition-all border border-slate-300"
                  >
                    <RefreshCcw className="w-4 h-4" />
                    Nouvelle analyse
                  </button>
                </div>
                {results.length > 1 ? (
                   <MultiMatchResultView results={results} />
                ) : currentResult ? (
                   <MatchResultView result={currentResult} candidateName="Candidat" />
                ) : (
                   <div className="text-center py-20 text-slate-400 font-bold uppercase tracking-widest">Initialisation...</div>
                )}
              </div>
            ) : (
              <MatchingDashboard onPaywallOpen={() => setIsPaywallOpen(true)} />
            )}
          </div>
        ) : activeTab === 'vivier' ? (
          <div className="space-y-8">
            <VivierManager />
          </div>
        ) : activeTab === 'historique' ? (
          <div className="bg-white rounded-[2.5rem] p-8 shadow-2xl shadow-slate-300 border border-slate-200 overflow-hidden min-h-[500px]">
            <HistoryList onSelectAnalysis={(res: MatchResult) => {
              dispatch(setResult(res));
              setActiveTab('analyse');
            }} />
          </div>
        ) : (
          <SubscriptionManager 
            userId={user.id}
            userPlan={user.plan || 'FREE'}
            subStatus={user.subscriptionStatus || 'INACTIVE'}
            nextBillingDate={user.nextBillingDate}
            credits={credits}
          />
        )}

        {/* Pied de page du Dashboard */}
        <div className="mt-12 flex flex-col md:flex-row items-center justify-between text-muted text-[10px] font-bold uppercase tracking-widest px-4">
          <div className="flex items-center gap-6 mb-4 md:mb-0">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
              <span>Système IA Opérationnel</span>
            </div>
            <div className="flex items-center gap-2">
              <History className="w-4 h-4" />
              <span>Historique Sauvegardé</span>
            </div>
          </div>
          <p>© 2026 TalentPulse - Advanced AI Suite</p>
        </div>
      </div>

      <PaywallModal 
        isOpen={isPaywallOpen} 
        onClose={() => setIsPaywallOpen(false)} 
      />
      </main>
    </div>
  );
}

function TabButton({ active, onClick, icon, label }: { active: boolean, onClick: () => void, icon: React.ReactNode, label: string }) {
  return (
    <button 
      onClick={onClick}
      className={`
        flex items-center gap-2 px-6 py-2 rounded-lg font-bold text-sm transition-all border
        ${active ? 'bg-white text-primary shadow-md border-slate-300' : 'text-slate-600 hover:text-main border-transparent'}
      `}
    >
      {icon}
      {label}
    </button>
  );
}

"use client";

import React, { useEffect, useState } from 'react';
import { useAuth } from '@/hooks/useAuth';
import { getUserHistoryAction } from '@/actions/history.action';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';
import { 
  History, 
  FileSearch, 
  ChevronRight, 
  Search, 
  Calendar,
  AlertCircle
} from 'lucide-react';
import { MatchResult } from '@/lib/ai';

import Pagination from './Pagination';

interface HistoryRecord {
  id: string;
  userId: string;
  candidateName: string;
  jobTitle: string;
  score: number;
  aiResponse: MatchResult;
  createdAt: string;
  mission?: { description: string };
  candidate?: Record<string, unknown>;
}

interface HistoryListProps {
  onSelectAnalysis: (result: MatchResult) => void;
}

export default function HistoryList({ onSelectAnalysis }: HistoryListProps) {
  const { user, token } = useAuth();
  const [records, setRecords] = useState<HistoryRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [isChangingPage, setIsChangingPage] = useState(false);

  const fetchHistory = async (page: number) => {
    if (!token || !user?.id) return;

    setIsChangingPage(true);
    try {
      const res = await getUserHistoryAction(user.id, token, page, 20);
      if (res.success && res.records) {
        setRecords(res.records as unknown as HistoryRecord[]);
        setTotalPages(res.totalPages || 1);
        setCurrentPage(page);
      }
    } catch (error) {
      console.error("Erreur chargement historique:", error);
    } finally {
      setLoading(false);
      setIsChangingPage(false);
      // Remonter en haut de la liste lors du changement de page
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  useEffect(() => {
    fetchHistory(1);

    // Sécurité : Si après 3 secondes on charge toujours, on libère le spinner
    const timer = setTimeout(() => setLoading(false), 3000);
    return () => clearTimeout(timer);
  }, [token, user?.id]);

  const handlePageChange = (newPage: number) => {
    fetchHistory(newPage);
  };

  const filteredRecords = records.filter(r => 
    r.jobTitle.toLowerCase().includes(searchTerm.toLowerCase()) ||
    r.candidateName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 gap-4">
        <div className="w-12 h-12 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div>
        <p className="text-muted font-bold text-sm tracking-widest uppercase">Chargement de votre historique...</p>
      </div>
    );
  }

  if (records.length === 0 && !searchTerm) {
    return (
      <div className="text-center py-20">
        <div className="inline-flex p-6 bg-slate-100 rounded-full mb-6">
          <History className="w-10 h-10 text-slate-400" />
        </div>
        <h3 className="text-xl font-bold text-main mb-2">Aucun historique trouvé</h3>
        <p className="text-muted text-sm max-w-sm mx-auto">
          Vous n&apos;avez pas encore effectué d&apos;analyse de matching. Commencez dès maintenant pour voir vos résultats ici.
        </p>
      </div>
    );
  }

  return (
    <div className={`space-y-6 transition-opacity duration-300 ${isChangingPage ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-main flex items-center gap-3">
            <History className="w-6 h-6 text-primary" />
            Historique des analyses
          </h2>
          <p className="text-muted text-sm font-medium">Retrouvez et rouvrez vos matchings précédents.</p>
        </div>

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted" />
          <input 
            type="text"
            placeholder="Rechercher une analyse..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2.5 bg-slate-100 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-primary w-full md:w-64 transition-all"
          />
        </div>
      </div>

      <div className="grid gap-4">
        {filteredRecords.map((record) => (
          <div 
            key={record.id}
            onClick={() => onSelectAnalysis({
              ...record.aiResponse,
              jobTitle: record.jobTitle,
              jobDescription: record.mission?.description,
              fullCandidate: record.candidate
            })}
            className="group relative bg-white border border-slate-200 p-5 rounded-2xl cursor-pointer hover:border-primary hover:shadow-xl hover:shadow-primary/5 transition-all"
          >
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex items-start gap-4">
                <div className={`p-3 rounded-xl ${
                  record.score >= 70 ? 'bg-emerald-50 text-emerald-600' : 
                  record.score >= 40 ? 'bg-amber-50 text-amber-600' : 
                  'bg-red-50 text-red-600'
                }`}>
                  <FileSearch className="w-6 h-6" />
                </div>
                <div>
                  <h4 className="font-bold text-main group-hover:text-primary transition-colors text-lg">
                    {record.jobTitle}
                  </h4>
                  <p className="text-sm text-muted font-medium mb-2">Candidat : {record.candidateName}</p>
                  <div className="flex items-center gap-4 text-[10px] font-bold uppercase tracking-widest text-slate-400">
                    <span className="flex items-center gap-1.5 font-bold">
                      <Calendar className="w-3 h-3" />
                      {format(new Date(record.createdAt), 'dd MMMM yyyy (HH:mm)', { locale: fr })}
                    </span>
                  </div>
                </div>
              </div>

              <div className="flex items-center justify-between md:justify-end gap-6">
                <div className="text-right">
                  <div className={`text-2xl font-black ${
                    record.score >= 70 ? 'text-emerald-500' : 
                    record.score >= 40 ? 'text-amber-500' : 
                    'text-red-500'
                  }`}>
                    {Math.round(record.score)}%
                  </div>
                  <div className="text-[10px] font-bold text-muted uppercase tracking-tighter">Matching IA</div>
                </div>
                <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-primary group-hover:text-white transition-all shadow-inner">
                  <ChevronRight className="w-5 h-5" />
                </div>
              </div>
            </div>
          </div>
        ))}

        {filteredRecords.length === 0 && searchTerm && (
          <div className="flex flex-col items-center py-10 text-muted opacity-60">
            <AlertCircle className="w-8 h-8 mb-2" />
            <p className="text-sm font-medium">Aucune analyse ne correspond à votre recherche.</p>
          </div>
        )}
      </div>

      {/* Pagination AJAX */}
      <Pagination 
        currentPage={currentPage}
        totalPages={totalPages}
        onPageChange={handlePageChange}
        loading={isChangingPage}
      />
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { Search, Send, User, Clock, MessageSquare, Check, CheckCheck } from "lucide-react";
import { getAdminChatListAction, getMessagesAction, sendMessageAction, markAsReadAction } from "@/actions/chat.action";
import { format } from "date-fns";
import { fr } from "date-fns/locale";

interface Conversation {
  id: string;
  userId: string;
  updatedAt: Date;
  user: {
    email: string;
    firstName: string | null;
    lastName: string | null;
  };
  messages: {
    content: string;
    createdAt: Date;
    senderId: string;
    isRead: boolean;
  }[];
}

interface Message {
  id: string;
  content: string;
  senderRole: "USER" | "ADMIN";
  createdAt: Date;
  isRead: boolean;
  conversationId: string;
}

export default function AdminChatExplorer({ token, initialUserId }: { token: string, initialUserId?: string }) {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedUser, setSelectedUser] = useState<string | null>(initialUserId || null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState("");
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const scrollRef = useRef<HTMLDivElement>(null);

  // Charger la liste des conversations
  const fetchConversations = useCallback(async () => {
    const res = await getAdminChatListAction(token);
    if (res.success && res.conversations) {
      setConversations(res.conversations as any);

      // Si on a un userId initial (depuis le mail), on le sélectionne
      if (initialUserId && !selectedUser) {
        setSelectedUser(initialUserId);
      }
    }
  }, [token, initialUserId, selectedUser]);

  // Charger les messages de l'utilisateur sélectionné
  const fetchMessages = useCallback(async () => {
    if (!selectedUser) return;
    const res = await getMessagesAction(token, selectedUser);
    if (res.success && res.messages) {
      setMessages(res.messages as any);

      // Marquer comme lu
      const conv = conversations.find(c => c.userId === selectedUser);
      if (conv) {
        markAsReadAction(token, conv.id);
      }
    }
  }, [token, selectedUser, conversations]);

  useEffect(() => {
    queueMicrotask(() => {
      fetchConversations();
    });
    const interval = setInterval(fetchConversations, 15000); // 15s pour la liste
    return () => clearInterval(interval);
  }, [fetchConversations]);

  useEffect(() => {
    queueMicrotask(() => {
      fetchMessages();
    });
    const interval = setInterval(fetchMessages, 8000); // 8s pour le chat actif
    return () => clearInterval(interval);
  }, [fetchMessages]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() || !selectedUser || loading) return;

    setLoading(true);
    const res = await sendMessageAction(token, newMessage, selectedUser);
    if (res.success) {
      setNewMessage("");
      fetchMessages();
      fetchConversations();
    }
    setLoading(false);
  };

  const filteredConversations = conversations.filter(c => 
    c.user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    `${c.user.firstName} ${c.user.lastName}`.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="flex h-[700px] bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl animate-fadeIn">
      {/* Sidebar - Liste des Utilisateurs */}
      <div className="w-1/3 border-r border-slate-800 flex flex-col bg-slate-900/50">
        <div className="p-6 border-b border-slate-800">
          <h2 className="text-xl font-bold text-white mb-4">Conversations</h2>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
            <input 
              type="text"
              placeholder="Rechercher un utilisateur..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-slate-800 border border-slate-700 rounded-xl text-sm text-white focus:ring-2 focus:ring-blue-500 transition-all outline-none"
            />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto">
          {filteredConversations.length === 0 ? (
            <div className="p-8 text-center text-slate-500 text-sm">
              Aucune conversation trouvée.
            </div>
          ) : (
            filteredConversations.map((conv) => {
              const lastMsg = conv.messages[0];
              const isSelected = selectedUser === conv.userId;
              const hasUnread = lastMsg && !lastMsg.isRead && lastMsg.senderId === conv.userId;

              return (
                <button
                  key={conv.id}
                  onClick={() => setSelectedUser(conv.userId)}
                  className={`w-full p-4 flex items-center gap-4 transition-all border-b border-slate-800/50 hover:bg-slate-800/50 ${
                    isSelected ? 'bg-blue-600/10 border-l-4 border-l-blue-500' : 'border-l-4 border-l-transparent'
                  }`}
                >
                  <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg ${
                    isSelected ? 'bg-blue-500 text-white' : 'bg-slate-800 text-slate-400'
                  }`}>
                    {(conv.user.firstName?.[0] || conv.user.email[0]).toUpperCase()}
                  </div>
                  <div className="flex-1 text-left min-w-0">
                    <div className="flex justify-between items-start mb-1">
                      <p className={`font-semibold truncate text-sm ${isSelected ? 'text-blue-400' : 'text-white'}`}>
                        {conv.user.firstName} {conv.user.lastName}
                      </p>
                      {lastMsg && (
                        <span className="text-[10px] text-slate-500 whitespace-nowrap">
                          {format(new Date(conv.updatedAt), 'HH:mm', { locale: fr })}
                        </span>
                      )}
                    </div>
                    <div className="flex items-center justify-between">
                      <p className={`text-xs truncate ${hasUnread ? 'text-white font-bold' : 'text-slate-500'}`}>
                        {lastMsg ? lastMsg.content : "Nouvelle conversation"}
                      </p>
                      {hasUnread && (
                        <span className="w-2 h-2 bg-blue-500 rounded-full shadow-lg shadow-blue-500/50"></span>
                      )}
                    </div>
                  </div>
                </button>
              );
            })
          )}
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col bg-slate-900/30">
        {selectedUser ? (
          <>
            {/* Chat Header */}
            <div className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-900">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-blue-500/20 text-blue-400 flex items-center justify-center font-bold">
                  {conversations.find(c => c.userId === selectedUser)?.user.email[0].toUpperCase()}
                </div>
                <div>
                  <p className="text-white font-semibold text-sm">
                    {conversations.find(c => c.userId === selectedUser)?.user.email}
                  </p>
                  <p className="text-[10px] text-slate-500 flex items-center gap-1">
                    Utilisateur actif
                  </p>
                </div>
              </div>
              <div className="flex gap-2">
                 {/* Actions d'en-tête si besoin */}
              </div>
            </div>

            {/* Messages Scroll Area */}
            <div 
              ref={scrollRef}
              className="flex-1 overflow-y-auto p-6 space-y-6"
            >
              {messages.map((msg) => (
                <div 
                  key={msg.id} 
                  className={`flex flex-col ${msg.senderRole === 'ADMIN' ? 'items-end' : 'items-start'}`}
                >
                  <div className={`max-w-[70%] p-4 rounded-3xl shadow-lg relative transition-all hover:scale-[1.01] ${
                    msg.senderRole === 'ADMIN' 
                      ? 'bg-blue-600 text-white rounded-tr-none' 
                      : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-none'
                  }`}>
                    <p className="text-sm leading-relaxed">{msg.content}</p>
                    <div className={`flex items-center gap-1.5 mt-2 opacity-60 text-[10px] ${msg.senderRole === 'ADMIN' ? 'justify-end' : 'justify-start'}`}>
                      <Clock className="w-3 h-3" />
                      {format(new Date(msg.createdAt), 'dd MMM HH:mm', { locale: fr })}
                      {msg.senderRole === 'ADMIN' && (
                        msg.isRead ? <CheckCheck className="w-3 h-3 text-emerald-400" /> : <Check className="w-3 h-3" />
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Response Input */}
            <div className="p-6 border-t border-slate-800 bg-slate-900">
              <form onSubmit={handleSend} className="flex gap-3 items-center">
                <input 
                  type="text"
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  placeholder="Écrivez votre réponse..."
                  className="flex-1 bg-slate-800 border border-slate-700 rounded-2xl px-5 py-3 text-white focus:ring-2 focus:ring-blue-500 transition-all outline-none shadow-inner"
                />
                <button 
                  type="submit"
                  disabled={loading || !newMessage.trim()}
                  className="bg-blue-600 hover:bg-blue-500 text-white p-3.5 rounded-2xl transition-all shadow-lg shadow-blue-600/20 disabled:opacity-50 active:scale-95"
                >
                  <Send className="w-6 h-6" />
                </button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-500 space-y-4">
            <div className="p-6 bg-slate-800/50 rounded-full border border-slate-700">
              <MessageSquare className="w-12 h-12 text-slate-400" />
            </div>
            <p className="text-lg font-medium">Sélectionnez une conversation pour commencer</p>
            <p className="text-sm">Vous recevrez des notifications ici dès qu&apos;un utilisateur vous contacte.</p>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

